// ============================================================================
// Trade color helper
// ============================================================================
function getTradeColor(trade) {
    if (!trade) return {
        bg: 'bg-gray-100',
        text: 'text-gray-700',
        border: 'border-gray-200'
    };
    const t = trade.toLowerCase();
    if (t.includes('electric')) return {
        bg: 'bg-blue-100',
        text: 'text-blue-800',
        border: 'border-blue-200'
    };
    if (t.includes('mechan') || t.includes('fitter')) return {
        bg: 'bg-orange-100',
        text: 'text-orange-800',
        border: 'border-orange-200'
    };
    if (t.includes('civil') || t.includes('construct')) return {
        bg: 'bg-amber-100',
        text: 'text-amber-800',
        border: 'border-amber-200'
    };
    if (t.includes('instrum') || t.includes('iot')) return {
        bg: 'bg-cyan-100',
        text: 'text-cyan-800',
        border: 'border-cyan-200'
    };
    if (t.includes('weld')) return {
        bg: 'bg-red-100',
        text: 'text-red-800',
        border: 'border-red-200'
    };
    if (t.includes('workshop') || t.includes('machine')) return {
        bg: 'bg-purple-100',
        text: 'text-purple-800',
        border: 'border-purple-200'
    };
    if (t.includes('hse') || t.includes('safety')) return {
        bg: 'bg-rose-100',
        text: 'text-rose-800',
        border: 'border-rose-200'
    };
    if (t.includes('quality') || t.includes('inspect')) return {
        bg: 'bg-teal-100',
        text: 'text-teal-800',
        border: 'border-teal-200'
    };
    if (t.includes('store') || t.includes('supply') || t.includes('logistics')) return {
        bg: 'bg-indigo-100',
        text: 'text-indigo-800',
        border: 'border-indigo-200'
    };
    if (t.includes('prod') || t.includes('operat')) return {
        bg: 'bg-emerald-100',
        text: 'text-emerald-800',
        border: 'border-emerald-200'
    };
    if (t.includes('engineer')) return {
        bg: 'bg-sky-100',
        text: 'text-sky-800',
        border: 'border-sky-200'
    };
    return {
        bg: 'bg-gray-100',
        text: 'text-gray-700',
        border: 'border-gray-200'
    };
}
